function OrbitalIcons({ tab }) {
  const icons = ORBITAL_ICONS[tab] || ORBITAL_ICONS.Development;
  const R = 120; // orbit radius
  const SIZE = 310;
  const cx = SIZE / 2, cy = SIZE / 2;

  return (
    <div style={{ position: "relative", width: SIZE, height: SIZE }}>
      {/* Outer dashed orbit ring */}
      <svg style={{ position: "absolute", inset: 0 }} width={SIZE} height={SIZE}>
        <circle cx={cx} cy={cy} r={R} fill="none"
          stroke="rgba(20,184,166,0.18)" strokeWidth="1"
          strokeDasharray="6 5" />
        {/* Inner decorative ring */}
        <circle cx={cx} cy={cy} r={R * 0.55} fill="none"
          stroke="rgba(6,182,212,0.12)" strokeWidth="1"
          strokeDasharray="4 6" />
        {/* Glow center */}
        <circle cx={cx} cy={cy} r={48} fill="rgba(20,184,166,0.04)"
          stroke="rgba(20,184,166,0.25)" strokeWidth="1.2" />
      </svg>

      {/* Center laptop icon */}
      <div style={{
        position: "absolute",
        top: "50%", left: "50%",
        transform: "translate(-50%,-50%)",
        width: 78, height: 78,
        borderRadius: "50%",
        background: "rgba(20,184,166,0.08)",
        border: "1.5px solid rgba(20,184,166,0.35)",
        display: "flex", alignItems: "center", justifyContent: "center",
        boxShadow: "0 0 32px rgba(20,184,166,0.2)",
      }}>
        <svg width="34" height="34" viewBox="0 0 24 24" fill="none" stroke={T.teal} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
          <rect x="2" y="4" width="20" height="13" rx="2" />
          <polyline points="8,21 12,17 16,21" />
          <line x1="8" y1="17" x2="16" y2="17" />
          <polyline points="9,9 12,12 15,9" />
        </svg>
      </div>

      {/* Orbiting icons */}
      {icons.map((ic, i) => {
        const angle = (360 / icons.length) * i - 90; // start from top
        const rad = (angle * Math.PI) / 180;
        const x = cx + R * Math.cos(rad);
        const y = cy + R * Math.sin(rad);
        return (
          <div key={ic.label} style={{
            position: "absolute",
            left: x - 24, top: y - 24,
            width: 48, height: 48,
            borderRadius: "50%",
            background: ic.bg,
            border: `1.5px solid ${ic.color}55`,
            display: "flex", alignItems: "center", justifyContent: "center",
            boxShadow: `0 0 14px ${ic.color}40`,
            transition: "all .4s",
          }}>
            <span style={{ color: ic.color, fontSize: 12, fontWeight: 900, letterSpacing: -0.5 }}>{ic.symbol}</span>
          </div>
        );
      })}
    </div>
  );
}

// ─── TYPING CURSOR ────────────────────────────────────────
function TypedTitle() {
  const words = ["AI Researcher", "Deep Learning Engineer", "Full-Stack Developer", "Computer Vision Dev"];
  const [wi, setWi] = useState(0);
  const [ci, setCi] = useState(0);
  const [del, setDel] = useState(false);
  const [cursor, setCursor] = useState(true);
  useEffect(() => {
    const id = setInterval(() => setCursor(c => !c), 530);
    return () => clearInterval(id);
  }, []);
  useEffect(() => {
    const w = words[wi];
    if (!del && ci < w.length) {
      const t = setTimeout(() => setCi(c => c + 1), 70);
      return () => clearTimeout(t);
    }
    if (!del && ci === w.length) {
      const t = setTimeout(() => setDel(true), 1600);
      return () => clearTimeout(t);
    }
    if (del && ci > 0) {
      const t = setTimeout(() => setCi(c => c - 1), 40);
      return () => clearTimeout(t);
    }
    if (del && ci === 0) {
      setDel(false);
      setWi(i => (i + 1) % words.length);
    }
  }, [words]);
  return (
    <span style={{ color: T.teal, fontWeight: 700 }}>
      {words[wi].slice(0, ci)}
      <span style={{ opacity: cursor ? 1 : 0, color: T.teal2 }}>|</span>
    </span>
  );
}

